import {CLIENT_ID} from '../Config/Config'
import React, { useState, useEffect } from "react" ;
import { PayPalScriptProvider, PayPalButtons } from "@paypal/react-paypal-js";
import axios from 'axios';

const Checkout = () => {
    const [show, setShow] = useState(false);
    const [success, setSuccess] = useState(false);
    const [ErrorMessage, setErrorMessage] = useState("");
    const [orderID, setOrderID] = useState(false);
    var localdata=localStorage.getItem("item")
    // creates a paypal order
    const createOrder = (data, actions) => {
        return actions.order.create({
            purchase_units: [
                {
                    description: "PetShop",
                    amount: {
                        currency_code: "USD",
                        value: localdata,
                    },
                },
            ],
        }).then((orderID) => {
                setOrderID(orderID);
                console.log("ORDER ID:"+orderID)
                return orderID;
            });
    };

    function handleSubmit() {
        //e.preventDefault();

        const postData = {
            pid: localStorage.getItem("pid"),
        };

        axios({
          method:"POST",
          url:"http://localhost/Petshop/order.php",
          data:postData,
          headers:{ "Content-Type": "multipart/form-data" },
      }).then(()=>{
          alert("Data Inserted Successfully")
          //nevigate('')
      })
    }

    // check Approval
    const onApprove = (data, actions) => {
        return actions.order.capture().then(function (details) {
            const { payer } = details;
            setSuccess(true);
        });
    };

    //capture likely error
    const onError = (data, actions) => {
        setErrorMessage("An Error occured with your payment ");
    };

    useEffect(() => {
        if (success) {
            alert("Payment successful!!");
            console.log('Order successful . Your order id is--', orderID);
        }
    },[success]);

    return (
        <PayPalScriptProvider options={{ "client-id": CLIENT_ID }}>
            <center>
            <div>
                <div className="wrapper">
                    <div className="product-img">
                        <img
                            src="https://i.ibb.co/z53njjq/paypal-buttons-au.png"
                            alt="PetShop"
                            height="320"
                            width="300" />
                    </div>
                    <div className="product-info">
                        <div className="product-text">
                        <h1 style={{ color: 'green' }}>Thank You Done Success Payment at Petshop</h1>
                        </div>
                        <div className="product-price-btn">
                            <p>Rs.{localdata}</p>
                            <br></br>
                            <button className='buy-btn' type="submit" onClick={() => setShow(true)}>
                                Buy now
                            </button>
                        </div>
                    </div>
                </div>
                <br></br>
                {show ? (
                    <PayPalButtons
                        style={{ layout: "vertical" }}
                        createOrder={createOrder}
                        onApprove={onApprove}
                    />
                ) : null}
            </div>
            </center>
        </PayPalScriptProvider>
    );
}

export default Checkout
